<?php $editing=!!$product; ?><section class="admin-page-head"><div><p class="eyebrow">CATALOG / PRODUS</p><h1><?= $editing?'Editează produs':'Adaugă produs' ?></h1></div><a class="admin-button secondary" href="<?= $editing?e(url('/produs/'.$product['slug'])):'#' ?>" target="_blank">Previzualizare ↗</a></section><form class="admin-form-layout" method="post" enctype="multipart/form-data" action="<?= e(url($editing?'/admin/produse/'.$product['id']:'/admin/produse')) ?>"><?= csrf_field() ?><div><section class="admin-panel"><h2>Informații generale</h2><div class="admin-form-grid"><label>Nume produs<input name="name" required value="<?= e($product['name']??'') ?>"></label><label>Slug<input name="slug" value="<?= e($product['slug']??'') ?>" placeholder="generat din nume"></label><label>SKU principal<input name="sku" required value="<?= e($product['sku']??'') ?>"></label><label>Material<input name="material" value="<?= e($product['material']??'') ?>"></label><label class="wide">Descriere scurtă<textarea name="short_description"><?= e($product['short_description']??'') ?></textarea></label><label class="wide">Descriere HTML<textarea name="description_html"><?= e($product['description_html']??'') ?></textarea></label></div></section><section class="admin-panel"><div class="panel-head"><h2>Variante, preț și stoc</h2><button type="button" class="admin-button secondary" data-add-variant>Adaugă variantă</button></div><div data-variants><?php foreach($variants?:[['id'=>'','sku'=>$product['sku']??'','price_minor'=>0,'stock_qty'=>0]] as $variant): ?><div class="variant-row"><input type="hidden" name="variant_id[]" value="<?= e($variant['id']) ?>"><label>SKU variantă<input name="variant_sku[]" value="<?= e($variant['sku']) ?>" required></label><label>Preț (lei)<input type="number" step="0.01" name="variant_price[]" value="<?= number_format((int)$variant['price_minor']/100,2,'.','') ?>" required></label><label>Stoc<input type="number" name="variant_stock[]" value="<?= (int)$variant['stock_qty'] ?>" required></label></div><?php endforeach; ?></div></section><section class="admin-panel"><h2>SEO și pagină publică</h2><div class="admin-form-grid"><label class="wide">Meta title<input name="seo_title" value="<?= e($product['seo_title']??'') ?>"></label><label class="wide">Meta description<textarea name="seo_description"><?= e($product['seo_description']??'') ?></textarea></label><label class="check-label"><input type="checkbox" name="robots_index" value="1" <?= !isset($product['robots_index'])||$product['robots_index']?'checked':'' ?>> Index, follow</label><label class="check-label"><input type="checkbox" name="include_sitemap" value="1" <?= !isset($product['include_sitemap'])||$product['include_sitemap']?'checked':'' ?>> Include în sitemap</label></div></section></div><aside><section class="admin-panel"><h2>Publicare</h2><label>Status<select name="status"><option value="draft" <?= ($product['status']??'')==='draft'?'selected':'' ?>>Draft</option><option value="active" <?= ($product['status']??'')==='active'?'selected':'' ?>>Publicat</option><option value="archived" <?= ($product['status']??'')==='archived'?'selected':'' ?>>Arhivat</option></select></label><label class="check-label"><input type="checkbox" name="is_featured" value="1" <?= !empty($product['is_featured'])?'checked':'' ?>> Produs recomandat</label><button class="admin-button" type="submit">Salvează produsul</button></section><section class="admin-panel"><h2>Categorii asociate</h2><div class="category-checks"><?php foreach($categories as $category): ?><label><input type="checkbox" name="categories[]" value="<?= (int)$category['id'] ?>" <?= in_array($category['id'],$selected)?'checked':'' ?>> <?= e($category['name']) ?></label><?php endforeach; ?></div><label>Categorie principală<select name="primary_category_id" required><option value="">Alege</option><?php foreach($categories as $category): ?><option value="<?= (int)$category['id'] ?>" <?= (int)($product['primary_category_id']??0)===(int)$category['id']?'selected':'' ?>><?= e($category['name']) ?></option><?php endforeach; ?></select></label></section><section class="admin-panel"><h2>Imagine principală</h2><input type="file" name="image" accept="image/jpeg,image/png,image/webp"><p class="help">JPG, PNG sau WebP, maximum 8 MB.</p></section></aside></form>

